import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull with source object as first argument", () => {
  it("should extract source function from object with source property when used as pipeline source", () => {
    const emitted: number[] = [];
    const values = [1, 2, 3];
    let idx = 0;

    // A source function that emits values
    const sourceFunc = function(end: any, cb: Function) {
      if (end) return cb(end);
      if (idx >= values.length) return cb(true);
      cb(null, values[idx++]);
    };

    // An object with a .source property (like a duplex/through stream)
    const sourceObj = {
      source: sourceFunc
    };

    // A sink that collects values
    const sink = function(read: Function) {
      function drain() {
        read(null, function(end: any, data: any) {
          if (end === true) return;
          if (end) throw end;
          emitted.push(data);
          drain();
        });
      }
      drain();
    };

    // pull should recognize sourceObj has a .source and use sourceObj.source as the read fn
    pull(sourceObj, sink);

    expect(emitted).toEqual([1, 2, 3]);
  });
});
